From 2aa7e269ec7bc92d6f4dfa68392f6293905861d7 Mon Sep 17 00:00:00 2001
From: Sebastian Utz <su@rtme.net>
Date: Mon, 31 Mar 2025 13:46:19 +0200
Subject: [PATCH] Fix new column collection to not contain duplicates

Duplicated new columns weren't a real issue besides memory consumption
until the field limit detection on dynamically added columns was fixed
by https://github.com/crate/crate/commit/ea6fa68af2.

Fixes #17691.
---
 .../java/io/crate/execution/dml/Indexer.java  |  5 ++-
 .../io/crate/execution/dml/IndexerTest.java   | 41 +++++++++++++++++++
 2 files changed, 44 insertions(+), 2 deletions(-)

diff --git a/server/src/main/java/io/crate/execution/dml/Indexer.java b/server/src/main/java/io/crate/execution/dml/Indexer.java
index 3df5f13e95..6884d22467 100644
--- a/server/src/main/java/io/crate/execution/dml/Indexer.java
+++ b/server/src/main/java/io/crate/execution/dml/Indexer.java
@@ -31,6 +31,7 @@ import java.util.Collection;
 import java.util.Collections;
 import java.util.Comparator;
 import java.util.HashMap;
+import java.util.LinkedHashSet;
 import java.util.List;
 import java.util.Locale;
 import java.util.Map;
@@ -679,7 +680,7 @@ public class Indexer {
      * Looks for new columns in the values of the given IndexItem and returns them.
      */
     public List<Reference> collectSchemaUpdates(IndexItem item) throws IOException {
-        ArrayList<Reference> newColumns = new ArrayList<>();
+        LinkedHashSet<Reference> newColumns = new LinkedHashSet<>();
         Consumer<? super Reference> onDynamicColumn = ref -> {
             ref.column().validForCreate();
             newColumns.add(ref);
@@ -718,7 +719,7 @@ public class Indexer {
                 synthetics::get
             );
         }
-        return newColumns;
+        return newColumns.stream().toList();
     }

